initialize:
const listenPort = 8001;
const listenHost = "0.0.0.0";

const closeServer = (server) => {
    if (!server || typeof server.close !== "function") {
        return Promise.resolve();
    }

    try {
        if (typeof server.removeAllListeners === "function") {
            server.removeAllListeners("message");
            server.removeAllListeners("bundle");
            server.removeAllListeners("error");
            server.removeAllListeners("listening");
        }
    } catch (err) {
        node.warn("Error removing OSC listeners: " + err.message);
    }

    return new Promise((resolve) => {
        let doneCalled = false;
        const done = () => {
            if (doneCalled) return;
            doneCalled = true;
            resolve();
        };

        try {
            const maybePromise = server.close((err) => {
                if (err) node.warn("OSC close callback error: " + err.message);
                done();
            });

            if (maybePromise && typeof maybePromise.then === "function") {
                maybePromise.then(done).catch((err) => {
                    node.warn("OSC close promise error: " + err.message);
                    done();
                });
            } else {
                setTimeout(done, 150);
            }
        } catch (err) {
            node.warn("OSC close throw: " + err.message);
            done();
        }
    });
};

if (!nodeOsc || typeof nodeOsc.Server !== "function") {
    node.status({ fill: "red", shape: "ring", text: "node-osc missing" });
    node.error("node-osc not available. Enable functionExternalModules and deploy again.");
    return;
}

const normalizeBoolean = (value) => {
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value !== 0;
    const text = String(value).trim().toLowerCase();
    return text === "true" || text === "1" || text === "on";
};

const previousServer = context.get("oscServer");
context.set("oscServer", null);
node.status({ fill: "yellow", shape: "ring", text: "restarting OSC..." });

return closeServer(previousServer).then(() => {
    const oscServer = new nodeOsc.Server(listenPort, listenHost, function () {
        node.status({ fill: "green", shape: "dot", text: "OSC " + listenHost + ":" + listenPort });
    });

    context.set("oscServer", oscServer);

    oscServer.on("error", function (err) {
        node.warn("OSC server error: " + (err && err.message ? err.message : err));
    });

    oscServer.on("message", function (oscMsg) {
        if (!Array.isArray(oscMsg) || oscMsg.length < 2) return;

        const address = String(oscMsg[0] || "");
        const value = oscMsg[1];

        if (address === "/knx/switch") {
            node.send([{
                payload: normalizeBoolean(value),
                oscAddress: address,
                rawOsc: oscMsg
            }, null]);
            return;
        }

        if (address === "/knx/value") {
            const parsed = Number(value);
            if (!Number.isFinite(parsed)) {
                node.warn("OSC /knx/value not numeric: " + value);
                return;
            }

            node.send([null, {
                payload: Math.max(0, Math.min(255, Math.round(parsed))),
                oscAddress: address,
                rawOsc: oscMsg
            }]);
        }
    });
}).catch((err) => {
    node.status({ fill: "red", shape: "ring", text: "OSC start error" });
    node.error("Unable to start OSC server: " + (err && err.message ? err.message : err));
});

finalize:
const closeServer = (server) => {
    if (!server || typeof server.close !== "function") {
        return Promise.resolve();
    }

    try {
        if (typeof server.removeAllListeners === "function") {
            server.removeAllListeners("message");
            server.removeAllListeners("bundle");
            server.removeAllListeners("error");
            server.removeAllListeners("listening");
        }
    } catch (err) {
        node.warn("Error removing OSC listeners in finalize: " + err.message);
    }

    return new Promise((resolve) => {
        let doneCalled = false;
        const done = () => {
            if (doneCalled) return;
            doneCalled = true;
            resolve();
        };

        try {
            const maybePromise = server.close((err) => {
                if (err) node.warn("OSC finalize close callback error: " + err.message);
                done();
            });

            if (maybePromise && typeof maybePromise.then === "function") {
                maybePromise.then(done).catch((err) => {
                    node.warn("OSC finalize close promise error: " + err.message);
