                setTimeout(done, 150);
            }
        } catch (err) {
            node.warn("OSC finalize close throw: " + err.message);
            done();
        }
    });
};

const oscServer = context.get("oscServer");
context.set("oscServer", null);
node.status({ fill: "yellow", shape: "ring", text: "stopping OSC..." });

return closeServer(oscServer).then(() => {
    node.status({});
});
